  ('investigation-2b298e71-moex-00003', 'investigation-2b298e71', 'investigation-2b298e71-moex-114-de0a21a2', 'sub-investigation-2b298e71-01', NULL, 'essay', 'A擔任詐騙集團的取款車手。經被害人 B報案，檢察官安排 B與警方配
合，要求 B一方面虛與委蛇，依詐騙集團指示到超商門口付款，另一方
面指揮警察喬裝在旁埋伏，等待車手現身。詐騙集團與 B的約定時刻一
到，A出現並與B交談，B交付款項當下，喬裝警察一擁而上，以現行
犯逮捕 A。A 被帶回警局接受詢問。警察 C 先踐行刑事訴訟法第 95 條
第 1 項規定的權利告知，亦有詢問 A是否要委任辯護人，A簡單表示不
認識任何律師，也不願花錢聘請律師。警詢 20 分鐘後，C 始得知 A 具
原住民身分，仍繼續詢問，最終取得 A之自白。檢察官以加重詐欺罪起
訴 A。A 在法院主張本案存在違法誘捕偵查，又主張警詢自白乃違法取
證應無證據能力。請分析 A以上主張有無理由。（50 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:51+00:00", "source_pdf_sha1": "cd02707c0d90", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "403", "s": "0501", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "investigation", "civil_category": "調查工作組"}'::jsonb, NULL),
